import { useState, useEffect } from 'react';
import axiosClient from '../api/axiosClient';
import { toast } from 'react-toastify';
import useAuthStore from '../store/useAuthStore';
import { UserCircle, CalendarClock, Building } from 'lucide-react';

const Dashboard = () => {
    const { user } = useAuthStore();
    const [bookings, setBookings] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMyBookings();
    }, []);

    const fetchMyBookings = async () => {
        try {
            const res = await axiosClient.get('/bookings');
            setBookings(res.data.data);
            setLoading(false);
        } catch (err) {
            toast.error('Failed to load bookings');
            setLoading(false);
        }
    };

    const getStatusColor = (status) => {
        switch (status) {
            case 'Approved': return 'bg-green-100 text-green-800';
            case 'Rejected': return 'bg-red-100 text-red-800';
            case 'Pending': return 'bg-yellow-100 text-yellow-800';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    if (loading) return <div className="p-10 text-center">Loading dashboard...</div>;

    return (
        <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
            {/* Profile Header */}
            <div className="bg-white shadow rounded-xl p-6 mb-8 border border-gray-100 flex items-center gap-6">
                <div className="bg-indigo-100 p-4 rounded-full text-indigo-600">
                    <UserCircle size={64} />
                </div>
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Welcome, {user?.name}</h1>
                    <p className="text-gray-500">{user?.email}</p>
                    <div className="mt-2 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800 capitalize">
                        Role: {user?.role}
                    </div>
                </div>
            </div>

            {/* Bookings Section */}
            <div>
                <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center gap-2">
                    <CalendarClock className="text-indigo-600" /> My Booking Requests
                </h2>

                {bookings.length === 0 ? (
                    <div className="bg-white shadow rounded-xl p-10 text-center border border-gray-100">
                        <Building size={48} className="mx-auto text-gray-300 mb-4" />
                        <p className="text-gray-500 text-lg">You haven't requested any flats yet.</p>
                    </div>
                ) : (
                    <div className="bg-white shadow overflow-hidden sm:rounded-xl border border-gray-100">
                        <ul className="divide-y divide-gray-200">
                            {bookings.map((booking) => (
                                <li key={booking._id} className="p-6 hover:bg-gray-50 transition-colors">
                                    <div className="flex items-center justify-between">
                                        <div>
                                            <p className="text-sm font-medium text-indigo-600 truncate">
                                                Flat {booking.flat?.flatNumber} - {booking.flat?.tower?.name}
                                            </p>
                                            <div className="mt-2 flex items-center text-sm text-gray-500">
                                                <CalendarClock className="flex-shrink-0 mr-1.5 h-4 w-4 text-gray-400" />
                                                Requested Move-in: {new Date(booking.moveInDate).toLocaleDateString()}
                                            </div>
                                        </div>
                                        <div className="flex flex-col items-end gap-2">
                                            <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold ${getStatusColor(booking.status)}`}>
                                                {booking.status}
                                            </span>
                                            <span className="text-xs text-gray-500 font-medium">${booking.flat?.rent}/mo</span>
                                        </div>
                                    </div>
                                </li>
                            ))}
                        </ul>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Dashboard;

